DROP TABLE IF EXISTS `facturas_comerciales_his`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `facturas_comerciales_his` (
  `id_factura_comercial_his` int(11) NOT NULL AUTO_INCREMENT,
  `fecha` date DEFAULT NULL,
  `emisor` varchar(60) DEFAULT NULL,
  `precio` double DEFAULT NULL,
  `valor_nominal` decimal(10,2) DEFAULT NULL,
  `valor_efectivo` decimal(10,2) DEFAULT NULL,
  `fecha_emision` date DEFAULT NULL,
  `fecha_vencimiento` date DEFAULT NULL,
  `rendimiento` decimal(10,4) DEFAULT NULL,
  `procedencia` varchar(4) DEFAULT NULL,
  `observaciones` varchar(150) DEFAULT NULL,
  PRIMARY KEY (`id_factura_comercial_his`)
) ENGINE=InnoDB AUTO_INCREMENT=27161 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci COMMENT='Contiene el listado de facturas comerciales que se han negociado en la bolsa de valores desde enero de 2018 hasta la fecha';
