) ENGINE=InnoDB AUTO_INCREMENT=49775 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci COMMENT='Contiene el listado de papeles comerciales que se han negociado en la bolsa de valores desde enero de 2018 hasta la fecha';
